Here's a modern MSTest data-driven test example for your `PriceCalculator`:

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;

[TestClass]
public class PriceCalculatorTests
{
    private PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new PriceCalculator();

    // --- DataRow: inline test cases ---

    [TestMethod]
    [DataRow(10.0, 2, 20.0)]
    [DataRow(0.0, 5, 0.0)]
    [DataRow(9.99, 1, 9.99)]
    [DataRow(5.50, 3, 16.50)]
    public void CalculateTotal_ReturnsExpected(double price, int quantity, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)price, quantity);
        Assert.AreEqual((decimal)expected, result);
    }

    [TestMethod]
    [DataRow(100.0, 10.0, 90.0)]
    [DataRow(100.0, 0.0, 100.0)]
    [DataRow(50.0, 50.0, 25.0)]
    [DataRow(200.0, 100.0, 0.0)]
    public void ApplyDiscount_ReturnsExpected(double price, double discountPct, double expected)
    {
        var result = _calculator.ApplyDiscount((decimal)price, (decimal)discountPct);
        Assert.AreEqual((decimal)expected, result);
    }

    // --- DynamicData: complex/reusable test cases ---

    [TestMethod]
    [DynamicData(nameof(BulkTotalCases), DynamicDataSourceType.Method)]
    public void CalculateTotal_BulkCases(decimal price, int quantity, decimal expected)
    {
        var result = _calculator.CalculateTotal(price, quantity);
        Assert.AreEqual(expected, result);
    }

    private static IEnumerable<object[]> BulkTotalCases()
    {
        yield return new object[] { 1.00m, 100, 100.00m };
        yield return new object[] { 19.99m, 0, 0.00m };
        yield return new object[] { 0.01m, 1000, 10.00m };
    }

    [TestMethod]
    [DynamicData(nameof(InvalidDiscountCases), DynamicDataSourceType.Method)]
    public void ApplyDiscount_InvalidInput_Throws(decimal price, decimal discountPct)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(price, discountPct));
    }

    private static IEnumerable<object[]> InvalidDiscountCases()
    {
        yield return new object[] { 100m, -5m };   // negative discount
        yield return new object[] { 100m, 101m };  // over 100%
        yield return new object[] { -10m, 10m };   // negative price
    }
}
```

**Key best practices shown:**

| Technique | When to use |
|-----------|-------------|
| `[DataRow]` | Simple inline values (primitives only) |
| `[DynamicData]` | Complex types, large datasets, or shared cases |
| `DynamicDataSourceType.Method` | Preferred over `Property` for lazy evaluation |

**Notes:**
- `DataRow` doesn't support `decimal` literals directly — use `double` params and cast.
- `DynamicData` methods must be `static` and return `IEnumerable<object[]>`.
- Each `object[]` maps positionally to the test method parameters.
- Add `[DataRow(..., DisplayName = "descriptive name")]` for clearer test explorer output if needed.
